#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int x[N], y[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &x[i], &y[i]);
        }
        int points = N / 10;
        if (points == 0) {
            printf("-1\n");
        } else {
            double centroid_x = 0, centroid_y = 0;
            for (int i = 0; i < N; i++) {
                centroid_x += x[i];
                centroid_y += y[i];
            }
            centroid_x /= N;
            centroid_y /= N;
            for (int i = 0; i < points; i++) {
                double point_x = centroid_x + (i % 2 == 0 ? 1 : -1) * (i + 1);
                double point_y = centroid_y + (i % 2 == 0 ? 1 : -1) * (i + 1);
                printf("%.0f %.0f\n", point_x, point_y);
            }
        }
    }
    return 0;
}

