import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] x = new int[N];
            int[] y = new int[N];
            for (int i = 0; i < N; i++) {
                x[i] = sc.nextInt();
                y[i] = sc.nextInt();
            }
            int points = N / 10;
            if (points == 0) {
                System.out.println(-1);
            } else {
                double centroid_x = 0, centroid_y = 0;
                for (int i = 0; i < N; i++) {
                    centroid_x += x[i];
                    centroid_y += y[i];
                }
                centroid_x /= N;
                centroid_y /= N;
                for (int i = 0; i < points; i++) {
                    double point_x = centroid_x + (i % 2 == 0 ? 1 : -1) * (i + 1);
                    double point_y = centroid_y + (i % 2 == 0 ? 1 : -1) * (i + 1);
                    System.out.println((int)point_x + " " + (int)point_y);
                }
            }
        }
    }
}

